/* 汇编 trampoline: 保存内核上下文并进入用户态
 * 声明: void _enter_user_trampoline(uintptr_t entry, uintptr_t user_sp,
 *                                    uintptr_t satp_val, kernel_context_t *ctx)
 * 此函数:
 *   1. 保存 ra, sp 到 ctx
 *   2. 切换页表 (satp)
 *   3. 设置 sscratch = sp (内核 sp)
 *   4. sret 到用户态
 *   5. (用户进程 exit 后) 返回到调用者
 */
extern void _enter_user_trampoline(uintptr_t entry, uintptr_t user_sp,
                                    uintptr_t satp_val, kernel_context_t *ctx);

/* 链接脚本符号: 内核结束后的页 */
extern uint8_t _heap_start[];

kernel_context_t *get_kernel_context(void) {
    return &g_kernel_ctx;
}

void save_kernel_context(kernel_context_t *ctx) {
    ctx->satp = get_kernel_satp();
    /* sp 和 ra 由 trampoline 保存 */
}

