/* 内存块头部 */
typedef struct block_header {
    size_t size;              /* 块大小(含头部, 字节), bit0=1 表示已分配 */
    struct block_header *next; /* 空闲链表中的下一个 */
    struct block_header *prev; /* 空闲链表中的上一个 */
} block_t;

#define BLOCK_MAGIC     0xDEADBEEF
#define BLOCK_MIN_SIZE  32  /* 最小块大小 (含头部) */
#define BLOCK_ALIGN     16  /* 对齐边界 */

static uint8_t  heap_area[8 * 1024 * 1024];  /* 8MB 静态堆 */
static block_t *free_list = NULL;
static size_t   heap_size = 0;
static int      alloc_initialized = 0;

#define HEADER_SIZE ALIGN_UP(sizeof(block_t), BLOCK_ALIGN)
#define IS_FREE(b)  (((b)->size & 1) == 0)
#define SET_FREE(b)  ((b)->size &= ~1UL)
#define SET_USED(b)  ((b)->size |= 1UL)
#define GET_SIZE(b)  ((b)->size & ~1UL)
#define BLOCK_TO_DATA(b) ((void *)((uintptr_t)(b) + HEADER_SIZE))
#define DATA_TO_BLOCK(p) ((block_t *)((uintptr_t)(p) - HEADER_SIZE))
#define NEXT_BLOCK(b)    ((block_t *)((uintptr_t)(b) + GET_SIZE(b)))

